import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import axios from 'axios';
import toast from 'react-hot-toast';
import { LayoutDashboard, Calendar, Users, LogOut, Activity, User, Heart } from 'lucide-react';

const API = "http://localhost:5000/api";

export default function CaregiverDashboard() {
  const { user, logout } = useAuth();
  const navigate = useNavigate();

  const [activeTab, setActiveTab] = useState('overview');
  const [bookings, setBookings] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => { fetchBookings(); }, []);

  // ✅ FIXED: caregiver gets all bookings and filters
  const fetchBookings = async () => {
    const token = localStorage.getItem("token");

    try {
      const { data } = await axios.get(`${API}/bookings`, {
        headers: { Authorization: `Bearer ${token}` }
      });

      // ✅ Only show bookings assigned to this caregiver
      const myBookings = data.filter(
        b => b.caregiverId?.user?._id === user?.id || b.caregiverId?._id === user?.id
      );

      setBookings(myBookings);

    } catch (err) {
      console.log(err);
      toast.error('Failed to load bookings');
    } finally {
      setLoading(false);
    }
  };

  const updateStatus = async (id, status) => {
    const token = localStorage.getItem("token");

    try {
      await axios.patch(
        `${API}/bookings/${id}/status`,
        { status },
        { headers: { Authorization: `Bearer ${token}` } }
      );

      toast.success('Status updated');
      fetchBookings();

    } catch {
      toast.error('Failed to update status');
    }
  };

  const assigned = bookings.filter(b => b.status === 'assigned');
  const active = bookings.filter(b => b.status === 'active');
  const completed = bookings.filter(b => b.status === 'completed');

  return (
    <div className="dashboard-layout">

      {/* SIDEBAR */}
      <aside className="sidebar">
        <div className="sidebar-logo">
          <Heart size={18}/> Prana Solutions
        </div>

        <div className="sidebar-nav">
          <div className="sidebar-item" onClick={() => setActiveTab('overview')}>
            <LayoutDashboard size={18}/> Overview
          </div>
          <div className="sidebar-item" onClick={() => setActiveTab('patients')}>
            <Users size={18}/> Patients
          </div>
        </div>

        <div style={{ marginTop: 'auto' }}>
          <div className="sidebar-item" onClick={() => { logout(); navigate('/'); }}>
            <LogOut size={18}/> Logout
          </div>
        </div>
      </aside>

      {/* MAIN */}
      <main className="main-content">

        {/* OVERVIEW */}
        {activeTab === 'overview' && (
          <>
            <h1>Welcome {user?.name}</h1>

            <div className="stats-grid">
              <div className="card stat-card">
                <div className="stat-value">{bookings.length}</div>
                <div className="stat-label">Total</div>
              </div>
              <div className="card stat-card">
                <div className="stat-value">{assigned.length}</div>
                <div className="stat-label">Assigned</div>
              </div>
              <div className="card stat-card">
                <div className="stat-value">{active.length}</div>
                <div className="stat-label">Active</div>
              </div>
              <div className="card stat-card">
                <div className="stat-value">{completed.length}</div>
                <div className="stat-label">Completed</div>
              </div>
            </div>
          </>
        )}

        {/* PATIENTS */}
        {activeTab === 'patients' && (
          <>
            <h2>My Patients</h2>

            {loading ? (
              <p>Loading...</p>
            ) : bookings.length === 0 ? (
              <p>No assigned patients</p>
            ) : (
              bookings.map(b => (
                <div key={b._id} className="card" style={{ marginBottom: 10 }}>
                  <p><b>{b.patient?.name}</b></p>
                  <p>{b.careType}</p>
                  <p>Status: {b.status}</p>

                  {b.status === 'assigned' && (
                    <button onClick={() => updateStatus(b._id, 'active')}>
                      Start Care
                    </button>
                  )}

                  {b.status === 'active' && (
                    <button onClick={() => updateStatus(b._id, 'completed')}>
                      Complete Care
                    </button>
                  )}
                </div>
              ))
            )}
          </>
        )}

      </main>
    </div>
  );
}
